            aOrbiterC = ((aOrbiterC ^ aOrbiterF) ^ 1985617276755038416U) ^ aOrbiterUpdateSaltB[((aIndex + 27U)) & S_SALT1];
            aOrbiterC = RotL64((aOrbiterC * 8922441044704956113U), 29U);
            //
            aOrbiterG = ((aOrbiterG + aOrbiterI) + 12788438115317337513U) + aNonceWordJ;
            aOrbiterB = (aOrbiterB ^ aOrbiterG) ^ 12764254373118167946U;
            aOrbiterB = RotL64((aOrbiterB * 183912671907023411U), 23U);
